-- relation between orders and customers
CREATE TABLE orders (
  id INTEGER PRIMARY KEY,
  customer_id INTEGER NOT NULL REFERENCES customers(id)
);

const orders = [{id: 1, customer_id: 100}, {id: 2, customer_id: 101}];
const customers = [{id: 100, name: 'Alice'}, {id: 101, name: 'Bob'}];
const withCustomer = orders.map(o => ({
  ...o, customer: customers.find(c => c.id === o.customer_id)
}));

class Relation {
    int orderId;
    int customerId;
    String customerName;
}
List<Relation> relations = new ArrayList<>();

Dim orders As New List(Of Integer) From {1, 2}
Dim customers As New List(Of String) From {"Alice", "Bob"}
For Each orderId In orders
    Dim customer = customers(orderId - 1)
    Debug.Print(orderId & " -> " & customer)
Next
